from __future__ import annotations

import json
from pathlib import Path
from typing import Any

import pandas as pd


ROOT = Path(__file__).resolve().parents[2]
OFFLINE_DIR = ROOT / "webapp" / "offline_results"
LATENT_DIR = ROOT / "latent_vis"


def _read_csv_if_exists(path: Path) -> pd.DataFrame | None:
    if path.exists():
        return pd.read_csv(path)
    return None


def load_method_comparison() -> list[dict[str, Any]]:
    """Load method comparison from real pipeline outputs only."""
    rows: list[dict[str, Any]] = []

    # Real outputs generated by c.py
    summary_df = _read_csv_if_exists(ROOT / "tech_adversarial_grl_summary.csv")
    if summary_df is not None:
        for _, row in summary_df.iterrows():
            method = str(row["Method"])
            label_map = {
                "Baseline": "Baseline MLP (c.py)",
                "Gender_Adversarial": "Standalone adversarial baseline (c.py, gender)",
                "Intersectional_Adversarial": "Standalone adversarial baseline (c.py, intersectional)",
            }
            rows.append(
                {
                    "method": label_map.get(method, method),
                    "accuracy": float(row.get("Accuracy", float("nan"))),
                    "f1": float(row.get("F1_Score", float("nan"))),
                    "min_di": float(row.get("Min_DI", float("nan"))),
                    "source": "Generated by c.py",
                    "availability": "available",
                }
            )

    # Offline Fair CVAE outputs (if user generated through real code path)
    cvae_file = OFFLINE_DIR / "fair_cvae_results.json"
    if cvae_file.exists():
        payload = json.loads(cvae_file.read_text(encoding="utf-8"))
        rows.extend(payload.get("method_comparison", []))
    else:
        rows.extend(
            [
                {
                    "method": "Feature-removal baseline (more strict .py)",
                    "accuracy": None,
                    "f1": None,
                    "min_di": None,
                    "source": "Requires offline run of more strict .py",
                    "availability": "not_generated",
                },
                {
                    "method": "Fair CVAE adv_only (more strict .py)",
                    "accuracy": None,
                    "f1": None,
                    "min_di": None,
                    "source": "Requires offline run of more strict .py",
                    "availability": "not_generated",
                },
                {
                    "method": "Fair CVAE no_adv (more strict .py)",
                    "accuracy": None,
                    "f1": None,
                    "min_di": None,
                    "source": "Requires offline run of more strict .py",
                    "availability": "not_generated",
                },
                {
                    "method": "Fair CVAE full (more strict .py)",
                    "accuracy": None,
                    "f1": None,
                    "min_di": None,
                    "source": "Requires offline run of more strict .py",
                    "availability": "not_generated",
                },
            ]
        )

    return rows


def load_per_group_di_comparison() -> list[dict[str, Any]]:
    di_df = _read_csv_if_exists(ROOT / "tech_adversarial_grl_di_comparison.csv")
    if di_df is None:
        return []
    return di_df.to_dict(orient="records")


def load_latent_summary() -> dict[str, Any]:
    """Latent data must come from latent_vis outputs generated by real code."""
    cvae_file = OFFLINE_DIR / "fair_cvae_results.json"
    latent_rows: list[dict[str, Any]] = []
    note = "Latent outputs unavailable until offline Fair CVAE experiment is run from real code."

    if cvae_file.exists():
        payload = json.loads(cvae_file.read_text(encoding="utf-8"))
        latent_rows = payload.get("latent_metrics", [])
        note = "Latent metrics loaded from offline outputs generated through more strict .py + latent_vis.py."

    image_paths = []
    if LATENT_DIR.exists():
        for p in sorted(LATENT_DIR.glob("*.png")):
            image_paths.append(f"/latent_vis/{p.name}")

    return {"rows": latent_rows, "note": note, "images": image_paths}
